import{_ as a,o as n,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"62. Excess Annual Leave","description":"","frontmatter":{"title":"62. Excess Annual Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","annual-leave","hours","shift-work"]},"headers":[],"relativePath":"ebas/mspp/leave/62-excess-annual-leave.md","filePath":"ebas/mspp/leave/62-excess-annual-leave.md"}'),r={name:"ebas/mspp/leave/62-excess-annual-leave.md"};function s(i,e,l,p,c,h){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_62-excess-annual-leave" tabindex="-1">62. Excess Annual Leave <a class="header-anchor" href="#_62-excess-annual-leave" aria-label="Permalink to &quot;62. Excess Annual Leave&quot;">​</a></h1><p><strong>62.1</strong> Excessive leave accruals: general provision</p><p><strong>a.</strong> An employee has an excessive leave accrual if the employee has accrued more than 10 weeks paid annual leave (or 12 weeks paid annual leave for a shift workers).</p><p><strong>b.</strong> If an employee has an excessive leave accrual, the employer or the employee may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excessive leave accrual.</p><p><strong>c.</strong> The Employer must not unreasonably refuse to agree to a leave reduction plan, which includes saving leave for a special reason or for an extended vacation within 12 months.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>d.</strong> Once agreed, the leave reduction plan is to be in writing and signed by both the Employer and the Employee.</p><p><strong>62.2</strong> Excessive leave accruals: direction by Employer that leave be taken</p><p><strong>a.</strong> If an Employer has genuinely tried to reach agreement with an Employee, but agreement is not reached (including because the Employee refuses to confer), the Employer may direct the Employee in writing to take one or more periods of paid annual leave.</p><p><strong>b.</strong> However, in directing that the Employee take leave under this subclause 62.2a:</p><p><strong>(i)</strong> the Employee cannot be directed to reduce the accrued leave to less than eight (8) weeks;</p><p><strong>(ii)</strong> the Employer cannot require an Employee to take any period of paid annual leave of less than one week;</p><p><strong>(iii)</strong> the Employer cannot require the Employee to take a period of paid annual leave beginning less than 8 weeks or more than 12 months after the direction is given; and</p><p><strong>(iv)</strong> the direction must not be inconsistent with any leave arrangement agreed by the Employer and Employee.</p><p><strong>c.</strong> Where the Employer issues a direction to the Employee to take paid annual leave in accordance with this clause, the Employee must take paid annual leave in accordance with that direction.</p><p><strong>62.3</strong> Excessive leave accruals: notice by an Employee that leave be taken</p><p><strong>a.</strong> If an Employee has genuinely tried to reach agreement with an Employer, but agreement is not reached (including because the Employer refuses to confer), the Employee may give notice in writing to take one or more periods of paid annual leave.</p><p><strong>b.</strong> However, an Employee may only give a notice to the Employer to take leave if:</p><p><strong>(i)</strong> the Employee has had an excessive leave accrual for more than 6 months at the time of giving the notice; and</p><p><strong>(ii)</strong> the Employee has not been given a direction that when any other paid annual leave arrangements are taken into account, would eliminate the Employee’s excessive leave accrual (including arrangements by agreement or directions to take excessive annual leave).</p><p><strong>c.</strong> A notice given by an Employee must not:</p><p><strong>(i)</strong> if granted, result in the Employee’s remaining accrued entitlement to paid annual leave being at any time less than 6 weeks when any other paid annual leave arrangements are taken into account; or</p><p><strong>(ii)</strong> provide for the Employee to take any period of paid annual leave of less than one week; or</p><p><strong>(iii)</strong> provide for the Employee to take a period of paid annual leave beginning less than 8 weeks or more than 12 months, after the notice is given; or</p><p><strong>(iv)</strong> be inconsistent with any leave arrangement agreed by the Employer and Employee.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>d.</strong> An Employee is not entitled to request by a notice more than 4 weeks’ paid annual leave (or 5 weeks’ paid annual leave for a shift worker) in any period of 12 months.</p><p><strong>62.4</strong> Replacement of staff on annual leave If agreement is reached for the Employee to take one of more periods of excess annual leave, the Employer will have regard to the obligations contained in <a href="/eba/ebas/mspp/workforce-management/34-planned-and-unplanned-absences.html">clause 34</a> of this Agreement, which include backfill.</p><p>Plain language terms: excess leave, directed leave.</p>',29)])])}const d=a(r,[["render",s]]);export{g as __pageData,d as default};
